'use strict';

const path = require('path');
const fs = require('fs');

/**
 * A9 Tier 1 — PWA support, shared between the served viewer and the export.
 *
 * A site opts in via `viewer.pwa: true` in its config. Icons: a custom set
 * generated by the editor lives in `<dataDir>/sites/<site>/pwa/`; without one
 * the default feezal icons from `www/favicon/` are used.
 */

/** Generated icon files (whitelist — also guards the upload API). */
const PWA_ICON_FILES = [
    'icon-192.png',
    'icon-512.png',
    'apple-touch-icon.png',
    'maskable-192.png',
    'maskable-512.png',
];

/** Sizes for the manifest, keyed by file name. */
const ICON_SIZES = {
    'icon-192.png': '192x192',
    'icon-512.png': '512x512',
    'maskable-192.png': '192x192',
    'maskable-512.png': '512x512',
};

/** Default (feezal) icons shipped in www/favicon/, keyed by generated name. */
const DEFAULT_ICON_SOURCES = {
    'icon-192.png': 'web-app-manifest-192x192.png',
    'icon-512.png': 'web-app-manifest-512x512.png',
    'apple-touch-icon.png': 'apple-touch-icon.png',
};

const DEFAULT_BACKGROUND = '#1b1b1b';
const DEFAULT_THEME_COLOR = '#0284c7';

/** True when the site config opts into PWA behaviour. */
function pwaEnabled(config) {
    return Boolean(config && config.viewer && config.viewer.pwa);
}

/** Directory holding a site's generated icon set (may not exist). */
function pwaDir(dataDir, siteName) {
    return path.join(dataDir, 'sites', siteName, 'pwa');
}

/** True when a custom icon set has been generated for the site. */
function hasCustomIcons(dataDir, siteName) {
    if (!dataDir) return false;
    return fs.existsSync(path.join(pwaDir(dataDir, siteName), 'icon-192.png'));
}

/** Crop/background metadata stored next to the generated set. */
function readPwaMeta(dataDir, siteName) {
    try {
        return JSON.parse(fs.readFileSync(path.join(pwaDir(dataDir, siteName), 'pwa.json'), 'utf8'));
    } catch {
        return null;
    }
}

/** The www/favicon directory (dev: www/favicon, built: www/dist/favicon). */
function defaultIconDir(wwwDir) {
    for (const dir of [path.join(wwwDir, 'favicon'), path.join(wwwDir, 'dist', 'favicon')]) {
        if (fs.existsSync(dir)) return dir;
    }
    return null;
}

/**
 * Resolve an icon file to a path on disk — the site's custom set first, the
 * default feezal icons second. Returns null when unavailable (e.g. maskable
 * variants exist only in custom sets).
 */
function resolveIconFile(name, {dataDir, siteName, wwwDir}) {
    if (!PWA_ICON_FILES.includes(name)) return null;
    if (dataDir) {
        const custom = path.join(pwaDir(dataDir, siteName), name);
        if (fs.existsSync(custom)) return custom;
    }
    const fallback = DEFAULT_ICON_SOURCES[name];
    const dir = defaultIconDir(wwwDir);
    if (fallback && dir) {
        const p = path.join(dir, fallback);
        if (fs.existsSync(p)) return p;
    }
    return null;
}

/** All icons available for a site as [{name, file}] (custom or default). */
function availableIcons(opts) {
    return PWA_ICON_FILES
        .map(name => ({name, file: resolveIconFile(name, opts)}))
        .filter(icon => icon.file);
}

/**
 * Build the web-app manifest for a site.
 * @param {object} o {siteName, startUrl, scope, iconBase, icons, meta}
 *   icons: [{name, file}] — maskable entries get their own purpose.
 */
function buildManifest({siteName, startUrl, scope, iconBase, icons, meta}) {
    const backgroundColor = (meta && meta.backgroundColor) || DEFAULT_BACKGROUND;
    return {
        name: siteName,
        short_name: siteName,
        start_url: startUrl,
        scope,
        display: 'standalone',
        background_color: backgroundColor,
        theme_color: (meta && meta.backgroundColor) || DEFAULT_THEME_COLOR,
        icons: icons
            .filter(icon => ICON_SIZES[icon.name])
            .map(icon => ({
                src: iconBase + icon.name,
                sizes: ICON_SIZES[icon.name],
                type: 'image/png',
                // "any" and "maskable" stay separate entries — combining them
                // makes launchers crop the plain icon (double-crop artefact).
                purpose: icon.name.startsWith('maskable-') ? 'maskable' : 'any',
            })),
    };
}

/**
 * Minimal cache-first app-shell service worker.
 * Navigations go network-first with a cache fallback so updates arrive while
 * offline loads still work. Non-GET (incl. WebSocket upgrades) pass through.
 */
function buildServiceWorker({cacheName, shell}) {
    return `'use strict';
const CACHE = ${JSON.stringify(cacheName)};
const SHELL = ${JSON.stringify(shell)};
self.addEventListener('install', e => {
    e.waitUntil(caches.open(CACHE).then(c => c.addAll(SHELL)).then(() => self.skipWaiting()));
});
self.addEventListener('activate', e => {
    e.waitUntil(caches.keys()
        .then(keys => Promise.all(keys.filter(k => k !== CACHE).map(k => caches.delete(k))))
        .then(() => self.clients.claim()));
});
self.addEventListener('fetch', e => {
    if (e.request.method !== 'GET') return;
    if (e.request.mode === 'navigate') {
        e.respondWith(fetch(e.request)
            .then(res => { const copy = res.clone(); caches.open(CACHE).then(c => c.put(e.request, copy)); return res; })
            .catch(() => caches.match(e.request).then(hit => hit || caches.match(SHELL[0]))));
        return;
    }
    e.respondWith(caches.match(e.request).then(hit => hit || fetch(e.request)));
});
`;
}

/**
 * Inject the PWA tags into a viewer/export HTML page (before </head>) and the
 * service-worker registration (before </body>). `httpGuard` wraps the
 * registration so file:// exports skip it silently.
 */
function injectPwaTags(html, {manifestUrl, appleTouchIconUrl, themeColor, swUrl, swScope = null, httpGuard = false}) {
    const head = [
        `<link rel="manifest" href="${manifestUrl}">`,
        `<meta name="theme-color" content="${themeColor || DEFAULT_THEME_COLOR}">`,
        appleTouchIconUrl ? `<link rel="apple-touch-icon" href="${appleTouchIconUrl}">` : '',
    ].filter(Boolean).join('\n');
    const guard = httpGuard ? "location.protocol.startsWith('http') && " : '';
    // The viewer page lives at the scope path itself (/viewer/<site>), which
    // the sw.js default scope (/viewer/<site>/) would NOT cover — pass the
    // scope explicitly (the sw.js route sends Service-Worker-Allowed).
    const options = swScope ? `, {scope: '${swScope}'}` : '';
    const register =
        `<script>${guard}'serviceWorker' in navigator && ` +
        `navigator.serviceWorker.register('${swUrl}'${options}).catch(() => {});<` + '/script>';
    return html
        .replace('</head>', head + '\n</head>')
        .replace('</body>', register + '\n</body>');
}

/**
 * Register the per-site viewer PWA routes on an Express app:
 *   GET /viewer/:site/manifest.webmanifest
 *   GET /viewer/:site/sw.js
 *   GET /viewer/:site/icons/:file
 * All three 404 unless the site's config has viewer.pwa set.
 */
function registerPwaRoutes(app, {storage, wwwDir}) {
    // safe single path segment (mirrors the API's isValidSiteName)
    const safeName = n => typeof n === 'string' && n.length > 0 && n.length <= 128 &&
        !/[\\/]/.test(n) && !n.startsWith('.');
    const guard = async (req, res) => {
        if (!safeName(req.params.site)) { res.status(404).end(); return null; }
        try {
            const {config} = await storage.getSite(req.params.site);
            if (!pwaEnabled(config)) { res.status(404).end(); return null; }
            return config;
        } catch {
            res.status(404).end();
            return null;
        }
    };

    app.get('/viewer/:site/manifest.webmanifest', async (req, res) => {
        if (!(await guard(req, res))) return;
        const site = req.params.site;
        const opts = {dataDir: storage.dataDir, siteName: site, wwwDir};
        const manifest = buildManifest({
            siteName: site,
            startUrl: `/viewer/${encodeURIComponent(site)}`,
            scope: `/viewer/${encodeURIComponent(site)}`,
            iconBase: `/viewer/${encodeURIComponent(site)}/icons/`,
            icons: availableIcons(opts),
            meta: storage.dataDir ? readPwaMeta(storage.dataDir, site) : null,
        });
        res.type('application/manifest+json').json(manifest);
    });

    app.get('/viewer/:site/sw.js', async (req, res) => {
        if (!(await guard(req, res))) return;
        const site = req.params.site;
        const base = `/viewer/${encodeURIComponent(site)}`;
        const opts = {dataDir: storage.dataDir, siteName: site, wwwDir};
        const shell = [base, '/viewer-bundle.js',
            ...availableIcons(opts).map(icon => `${base}/icons/${icon.name}`)];
        res.set('Service-Worker-Allowed', base);
        res.type('text/javascript')
            .send(buildServiceWorker({cacheName: `feezal-pwa-${site}`, shell}));
    });

    // Icons are served regardless of the pwa flag (not sensitive, and the
    // editor previews them before the toggle has been deployed).
    app.get('/viewer/:site/icons/:file', (req, res) => {
        if (!safeName(req.params.site)) { res.status(404).end(); return; }
        const file = resolveIconFile(req.params.file, {
            dataDir: storage.dataDir, siteName: req.params.site, wwwDir,
        });
        if (!file) { res.status(404).end(); return; }
        res.sendFile(file);
    });
}

module.exports = {
    PWA_ICON_FILES,
    DEFAULT_ICON_SOURCES,
    DEFAULT_THEME_COLOR,
    pwaEnabled,
    pwaDir,
    hasCustomIcons,
    readPwaMeta,
    resolveIconFile,
    availableIcons,
    buildManifest,
    buildServiceWorker,
    injectPwaTags,
    registerPwaRoutes,
};
